package main

// Runtime glue benchmark for the GoScript-generated byte-slice, crypto, varint,
// and uint64 paths that show up in Spacewave unixfs image reads. The workload is
// deliberately small enough for a focused gate but keeps the issue anchor: about
// 3 MB total data, 512 KB chunks, AES-256-GCM, sha256, byte copy/proto-like
// varint decode, and a uint64 arithmetic loop.

import (
	"bytes"
	"crypto/aes"
	"crypto/cipher"
	"crypto/sha256"
	"encoding/binary"
	"fmt"
	"time"
)

const (
	chunkSize     = 512 * 1000
	numChunks     = 6
	reps          = 10
	protoFields   = 120_000
	u64Iterations = 5_000_000
	expectedU64   = uint64(7165182398461461145)
)

func fillDeterministic(b []byte, seed uint32) {
	x := seed
	for i := range b {
		x ^= x << 13
		x ^= x >> 17
		x ^= x << 5
		b[i] = byte(x)
	}
}

func sampleAcc(b []byte) uint64 {
	if len(b) == 0 {
		panic("empty sample")
	}
	return uint64(b[0]) + uint64(b[len(b)/2])<<8 + uint64(b[len(b)-1])<<16
}

func main() {
	totalMB := float64(chunkSize*numChunks) / 1e6

	key := make([]byte, 32)
	fillDeterministic(key, 0x12345678)
	blk, err := aes.NewCipher(key)
	if err != nil {
		panic(err)
	}
	gcm, err := cipher.NewGCM(blk)
	if err != nil {
		panic(err)
	}
	nonceSize := gcm.NonceSize()

	plain := make([][]byte, numChunks)
	cipherText := make([][]byte, numChunks)
	nonces := make([][]byte, numChunks)
	joinedPlain := make([]byte, chunkSize*numChunks)
	for i := range plain {
		p := make([]byte, chunkSize)
		fillDeterministic(p, 0x9e3779b9+uint32(i)*0x1000193)
		plain[i] = p
		copy(joinedPlain[i*chunkSize:], p)

		nonce := make([]byte, nonceSize)
		fillDeterministic(nonce, 0xa5a5a5a5+uint32(i)*0x45d9f3b)
		nonces[i] = nonce
		cipherText[i] = gcm.Seal(nil, nonce, p, nil)
	}

	expectedHashAcc := hashAccumulator(cipherText)
	expectedDecryptAcc := decryptAccumulator(gcm, nonces, cipherText, plain)
	expectedCopyAcc, _ := copyAccumulator(plain)
	protoBuf, expectedProtoAcc := buildProtoVarints(protoFields)
	expectedCopyDigest := sha256.Sum256(joinedPlain)

	tHash := time.Now()
	hashAcc := hashAccumulator(cipherText)
	hashMS := float64(time.Since(tHash).Microseconds()) / 1000.0
	if hashAcc != expectedHashAcc {
		panic(fmt.Sprintf("sha256 accumulator mismatch: got %d want %d", hashAcc, expectedHashAcc))
	}

	tDecrypt := time.Now()
	decryptAcc := decryptAccumulator(gcm, nonces, cipherText, plain)
	decryptMS := float64(time.Since(tDecrypt).Microseconds()) / 1000.0
	if decryptAcc != expectedDecryptAcc {
		panic(fmt.Sprintf("decrypt accumulator mismatch: got %d want %d", decryptAcc, expectedDecryptAcc))
	}

	tCopy := time.Now()
	copyAcc, copyDigest := copyAccumulator(plain)
	copyMS := float64(time.Since(tCopy).Microseconds()) / 1000.0
	if copyAcc != expectedCopyAcc || copyDigest != expectedCopyDigest {
		panic("copy output mismatch")
	}

	tProto := time.Now()
	var protoAcc uint64
	for range reps {
		acc, fields := decodeProtoVarints(protoBuf)
		if fields != protoFields {
			panic(fmt.Sprintf("proto field count mismatch: got %d want %d", fields, protoFields))
		}
		if acc != expectedProtoAcc {
			panic(fmt.Sprintf("proto accumulator mismatch: got %d want %d", acc, expectedProtoAcc))
		}
		protoAcc += acc
	}
	protoMS := float64(time.Since(tProto).Microseconds()) / 1000.0

	tU64 := time.Now()
	u64Acc := runUint64Loop()
	u64MS := float64(time.Since(tU64).Microseconds()) / 1000.0
	if u64Acc != expectedU64 {
		panic(fmt.Sprintf("uint64 accumulator mismatch: got %d want %d", u64Acc, expectedU64))
	}

	ops := reps * numChunks
	fmt.Printf("RESULT stage=copy mb=%.2f ops=%d total_ms=%.3f per_mb_ms=%.4f acc=%d check=ok\n",
		totalMB, ops, copyMS, copyMS/(totalMB*float64(reps)), copyAcc)
	fmt.Printf("RESULT stage=sha256 mb=%.2f ops=%d total_ms=%.3f per_mb_ms=%.4f acc=%d check=ok\n",
		totalMB, ops, hashMS, hashMS/(totalMB*float64(reps)), hashAcc)
	fmt.Printf("RESULT stage=aes_gcm_decrypt mb=%.2f ops=%d total_ms=%.3f per_mb_ms=%.4f acc=%d check=ok\n",
		totalMB, ops, decryptMS, decryptMS/(totalMB*float64(reps)), decryptAcc)
	protoMB := float64(len(protoBuf)) / 1e6
	fmt.Printf("RESULT stage=proto_varint_decode mb=%.2f records=%d total_ms=%.3f per_mb_ms=%.4f acc=%d check=ok\n",
		protoMB, reps*protoFields, protoMS, protoMS/(protoMB*float64(reps)), protoAcc)
	fmt.Printf("RESULT stage=uint64_loop iters=%d total_ms=%.3f per_miter_ms=%.4f acc=%d check=ok\n",
		u64Iterations, u64MS, u64MS/(float64(u64Iterations)/1e6), u64Acc)
}

func hashAccumulator(chunks [][]byte) uint64 {
	var acc uint64
	for range reps {
		for i := range chunks {
			sum := sha256.Sum256(chunks[i])
			acc += uint64(sum[0]) + uint64(sum[15])<<8 + uint64(sum[31])<<16
		}
	}
	return acc
}

func decryptAccumulator(gcm cipher.AEAD, nonces [][]byte, cipherText [][]byte, plain [][]byte) uint64 {
	var acc uint64
	for range reps {
		for i := range cipherText {
			out, err := gcm.Open(nil, nonces[i], cipherText[i], nil)
			if err != nil {
				panic(err)
			}
			if !bytes.Equal(out, plain[i]) {
				panic(fmt.Sprintf("decrypt plaintext mismatch at chunk %d", i))
			}
			acc += sampleAcc(out)
		}
	}
	return acc
}

func copyAccumulator(plain [][]byte) (uint64, [32]byte) {
	var acc uint64
	dst := make([]byte, chunkSize*numChunks)
	for range reps {
		for i := range plain {
			c := bytes.Clone(plain[i])
			if !bytes.Equal(c, plain[i]) {
				panic(fmt.Sprintf("clone mismatch at chunk %d", i))
			}
			if n := copy(dst[i*chunkSize:], c); n != len(c) {
				panic(fmt.Sprintf("short copy at chunk %d: %d", i, n))
			}
			acc += sampleAcc(c)
		}
	}
	return acc, sha256.Sum256(dst)
}

func buildProtoVarints(fields int) ([]byte, uint64) {
	buf := make([]byte, 0, fields*8)
	tmp := make([]byte, binary.MaxVarintLen64)
	var expected uint64
	for i := range fields {
		field := uint64(i%15) + 1
		key := field << 3
		value := (uint64(i)*1315423911 ^ uint64(i>>3)*2654435761) & ((uint64(1) << 35) - 1)

		n := binary.PutUvarint(tmp, key)
		buf = append(buf, tmp[:n]...)
		n = binary.PutUvarint(tmp, value)
		buf = append(buf, tmp[:n]...)
		expected += (field * 16777619) ^ value
	}
	return buf, expected
}

func decodeProtoVarints(buf []byte) (uint64, int) {
	var acc uint64
	off := 0
	fields := 0
	for off < len(buf) {
		key, n := binary.Uvarint(buf[off:])
		if n <= 0 {
			panic(fmt.Sprintf("invalid proto key at offset %d", off))
		}
		off += n
		if key&7 != 0 {
			panic(fmt.Sprintf("unexpected wire type %d", key&7))
		}

		value, n := binary.Uvarint(buf[off:])
		if n <= 0 {
			panic(fmt.Sprintf("invalid proto value at offset %d", off))
		}
		off += n
		field := key >> 3
		acc += (field * 16777619) ^ value
		fields++
	}
	return acc, fields
}

func runUint64Loop() uint64 {
	var acc uint64 = 1
	for range u64Iterations {
		acc = acc*6364136223846793005 + 1442695040888963407
		acc ^= acc >> 33
	}
	return acc
}
